// Transaction T1: Transfer $100 from Account A to B
void transactionT1(int accountA, int accountB, int amount) {
    // Acquire exclusive locks
    lock(accountA);  // Lock account A
    lock(accountB);  // Lock account B

    // Read current balances
    int balanceA = read(accountA);
    int balanceB = read(accountB);

    // Perform transfer
    balanceA = balanceA - amount;
    balanceB = balanceB + amount;

    // Write new balances
    write(accountA, balanceA);
    write(accountB, balanceB);

    // Release locks
    unlock(accountA);
    unlock(accountB);

    // Commit transaction
    commit();
}

// Transaction T2: Read balance of Account A
void transactionT2(int accountA) {
    // Try to acquire lock
    lock(accountA);

    // Read balance (will wait if T1 holds lock)
    int balanceA = read(accountA);

    // Release lock
    unlock(accountA);

    return balanceA;
}
